// Extract curriculum and course metadata
const courseData = $input.first().json;
const curriculum = courseData.curriculum;
const courseTitle = courseData.title;
const courseDescription = courseData.description;
const learningObjectives = courseData.learningObjectives;

// Create items for each lesson with relevant context
return curriculum.map((lesson, index) => ({
  json: {
    lesson: lesson,
    courseContext: {
      title: courseTitle,
      description: courseDescription.substring(0, 500) + '...', // Truncate for context
      learningObjectives: learningObjectives.slice(0, 5), // First 5 objectives
      totalLessons: curriculum.length
    },
    lessonNumber: index + 1,
    total_slides: 10
  }
}));

parameters.text:
=You are an AI presentation builder. Create slides for this specific lesson.

**CRITICAL: Return ONLY valid JSON array. Do NOT wrap in markdown code blocks or add any explanatory text.**

**Course Context:**
- Course: {{ $('Extract Lessons & Context').item.json.courseContext.title }}
- Lesson {{ $('Extract Lessons & Context').item.json.lessonNumber }} of {{ $('Extract Lessons & Context').item.json.courseContext.totalLessons }}

**Current Lesson Details:**
- Week: {{ $('Extract Lessons & Context').item.json.lesson.week }}
- Title: {{ $('Extract Lessons & Context').item.json.lesson.title }}
- Objective: {{ $('Extract Lessons & Context').item.json.lesson.objective }}
- Topics: {{ $('Extract Lessons & Context').item.json.lesson.topics.join(', ') }}
- Demo: {{ $('Extract Lessons & Context').item.json.lesson.demo }}
- Core Task: {{ $('Extract Lessons & Context').item.json.lesson.core_task }}
- Sub Tasks: {{ $('Extract Lessons & Context').item.json.lesson.sub_tasks.join('; ') }}

Generate {{ $('Extract Lessons & Context').item.json.total_slides }} slides. Structure should include:
- Slide 1: Title slide with lesson title and week number
- Slide 2: Learning objectives for this specific lesson
- Slides 3-8: Break down the topics, demo, and tasks into digestible content
- Slide 9: Core task and sub-tasks summary
- Slide 10: Next steps or key takeaways

**RETURN FORMAT - Start your response with [ and end with ]:**
[
  {
    "title": "Slide Title",
    "subtitle": "Slide Subtitle",
    "bullets": ["Point 1", "Point 2", "Point 3", "Point 4", "Point 5"]
  }
]

Each slide must have exactly 5 bullet points. Response must be valid JSON only - no markdown, no explanations, no code blocks.

