let output = $input.item.json.output;

// Clean up potential markdown formatting
output = output.replace(/^```json\s*/, ''); // Remove opening ```json
output = output.replace(/\s*```$/, ''); // Remove closing ```
output = output.replace(/^```\s*/, ''); // Remove opening ``` 
output = output.trim(); // Remove whitespace

// Ensure it starts with [ and ends with ]
if (!output.startsWith('[')) {
  throw new Error('AI output does not start with [. Output: ' + output.substring(0, 100));
}
if (!output.endsWith(']')) {
  throw new Error('AI output does not end with ]. Output: ' + output.substring(output.length - 100));
}

try {
  const slides = JSON.parse(output);
  const lessonNumber = $('Loop Over Lessons').item.json.lessonNumber;
  const presentationId = $('Create Lesson Presentation').item.json.presentationId;;

  return slides.map((slide, index) => ({
    json: {
      ...slide,
      slideIndex: index,
      lessonNumber: lessonNumber,
      presentationId: presentationId,
    }
  }));
} catch (error) {
  throw new Error('Failed to parse AI output as JSON. Error: ' + error.message + '. Output: ' + output.substring(0, 200));
}
